INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmovii6ja000ctmm4k2nrxpwl', 'Mono-PE Recyclable Rollstock', 'Material en rollo reciclable Mono-PE', 'رولستوك أحادي PE قابل لإعادة التدوير', 'mono-pe-recyclable-rollstock', NULL, 'Material en rollo reciclable Mono-PE', 'رولستوك أحادي PE قابل لإعادة التدوير', NULL, 'Material en rollo reciclable Mono-PE', 'رولستوك أحادي PE قابل لإعادة التدوير', 'cmovii68y0004tmm4qtfet8ep', '/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/1.png', '["/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/1.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/2.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/3.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/4.png"]', '["100% Recyclable","Sustainable","High Sealing Strength"]', '["100% reciclable","Sostenible","Alta fuerza de sellado"]', '["قابلة لإعادة التدوير بنسبة 100%","مستمر","قوة الختم العالية"]', '<div class="product-detailed-description">
  <h3>Product Overview</h3>
  <p>The <strong>Mono-PE Recyclable Rollstock</strong> is engineered to meet the highest industry standards for flexible packaging and functional applications. Utilizing advanced manufacturing processes, this material delivers exceptional performance tailored for specialized needs.</p>
  
  <h3>Key Characteristics</h3>
  <ul>
    <li><strong>Core Advantage:</strong> Sustainable</li>
    <li><strong>Application:</strong> High Sealing Strength</li>
    <li><strong>Original Spec:</strong> 100% Recyclable</li>
    <li><strong>Quality Assurance:</strong> Manufactured with precision to ensure uniform thickness, excellent barrier properties, and superior mechanical strength.</li>
  </ul>

  <h3>Why Choose Our Films?</h3>
  <p>Whether you require high-barrier properties for food preservation, specific metallic aesthetics for brand enhancement, or eco-friendly mono-materials to meet sustainability goals, our film series provides a reliable, cost-effective, and highly customizable solution. The material is compatible with various conversion processes including printing, lamination, and pouch making.</p>
</div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: column; gap: 20px;">
  <h3 style="margin-bottom: 20px; font-size: 24px; font-weight: bold;">Product Gallery</h3>
  <img src="/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/1.png" alt="Mono-PE Recyclable Rollstock" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
  <img src="/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/2.jpeg" alt="Mono-PE Recyclable Rollstock" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
  <img src="/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/3.jpeg" alt="Mono-PE Recyclable Rollstock" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
  <img src="/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/4.jpeg" alt="Mono-PE Recyclable Rollstock" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', '<div class="descripción-detallada-del-producto">
  <h3>Descripción general del producto</h3><p>El <strong>rollo reciclable mono-PE</strong> está diseñado para cumplir con los más altos estándares de la industria para embalajes flexibles y aplicaciones funcionales. Utilizando procesos de fabricación avanzados, este material ofrece un rendimiento excepcional adaptado a necesidades especializadas.</p><h3>Características clave</h3><ul>
    <li><strong>Ventaja principal:</strong> Sostenible</li><li><strong>Aplicación:</strong> Alta resistencia al sellado</li><li><strong>Especificaciones originales:</strong> 100% reciclable</li><li><strong>Garantía de calidad:</strong> Fabricado con precisión para garantizar un espesor uniforme, excelentes propiedades de barrera y una resistencia mecánica superior.</li></ul>

  <h3>¿Por qué elegir nuestras películas?</h3><p>Ya sea que necesite propiedades de alta barrera para la conservación de alimentos, una estética metálica específica para mejorar la marca o monomateriales ecológicos para cumplir los objetivos de sostenibilidad, nuestra serie de películas proporciona una solución confiable, rentable y altamente personalizable. El material es compatible con varios procesos de conversión, incluidos la impresión, la laminación y la fabricación de bolsas.</p></div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: columna; espacio: 20px;">
