INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmovin20s001ptmrgws1in574', 'Matte PET Film - YG/YGD', 'Película PET mate - YG/YGD', 'فيلم PET غير لامع - YG/YGD', 'matte-pet-film-yg-ygd', NULL, 'Película PET mate - YG/YGD', 'فيلم PET غير لامع - YG/YGD', NULL, 'Película PET mate - YG/YGD', 'فيلم PET غير لامع - YG/YGD', 'cmovii66i0003tmm4zk4s7tvy', '/products/specialty-functional-films/matte-pet-film-yg-ygd/1.png', '["/products/specialty-functional-films/matte-pet-film-yg-ygd/1.png"]', '["Corona Treated Options","Special Manufacturing Process"]', '["Opciones tratadas con corona","Proceso de fabricación especial"]', '["خيارات علاج كورونا","عملية التصنيع الخاصة"]', '<div class="product-detailed-description">
  <h3>Product Overview</h3>
  <p>The <strong>Matte PET Film - YG/YGD</strong> is engineered to meet the highest industry standards for flexible packaging and functional applications. Utilizing advanced manufacturing processes, this material delivers exceptional performance tailored for specialized needs.</p>
  
  <h3>Key Characteristics</h3>
  <ul>
    <li><strong>Core Advantage:</strong> Corona Treated Options</li>
    <li><strong>Application:</strong> Special Manufacturing Process</li>
    <li><strong>Original Spec:</strong> 原色亚光膜</li>
    <li><strong>Quality Assurance:</strong> Manufactured with precision to ensure uniform thickness, excellent barrier properties, and superior mechanical strength.</li>
  </ul>

  <h3>Why Choose Our Films?</h3>
  <p>Whether you require high-barrier properties for food preservation, specific metallic aesthetics for brand enhancement, or eco-friendly mono-materials to meet sustainability goals, our film series provides a reliable, cost-effective, and highly customizable solution. The material is compatible with various conversion processes including printing, lamination, and pouch making.</p>
</div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: column; gap: 20px;">
  <h3 style="margin-bottom: 20px; font-size: 24px; font-weight: bold;">Product Gallery</h3>
  <img src="/products/specialty-functional-films/matte-pet-film-yg-ygd/1.png" alt="Matte PET Film - YG/YGD" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', '<div class="descripción-detallada-del-producto">
  <h3>Descripción general del producto</h3><p>La <strong>película PET mate - YG/YGD</strong> está diseñada para cumplir con los más altos estándares de la industria para embalajes flexibles y aplicaciones funcionales. Utilizando procesos de fabricación avanzados, este material ofrece un rendimiento excepcional adaptado a necesidades especializadas.</p><h3>Características clave</h3><ul>
    <li><strong>Ventaja principal:</strong> Opciones tratadas con Corona</li><li><strong>Aplicación:</strong> Proceso de fabricación especial</li><li><strong>Especificaciones originales:</strong> Película mate de color original</li><li><strong>Garantía de calidad:</strong> Fabricado con precisión para garantizar un espesor uniforme, excelentes propiedades de barrera y una resistencia mecánica superior.</li></ul>

  <h3>¿Por qué elegir nuestras películas?</h3><p>Ya sea que necesite propiedades de alta barrera para la conservación de alimentos, una estética metálica específica para mejorar la marca o monomateriales ecológicos para cumplir los objetivos de sostenibilidad, nuestra serie de películas proporciona una solución confiable, rentable y altamente personalizable. El material es compatible con varios procesos de conversión, incluidos la impresión, la laminación y la fabricación de bolsas.</p></div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: columna; espacio: 20px;">
  <h3 style="margin-bottom: 20px; font-size: 24px; font-weight: negrita;">Galería de productos</h3><img src="/products/specialty-functional-films/matte-pet-film-yg-ygd/1.png" alt="Película PET mate - YG/YGD" style="ancho: 100%; ancho máximo: 800px; alto: automático; radio del borde: 8px; sombra del cuadro: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', '<div class="product-detailed-description">
  <h3>نظرة عامة على المنتج</h3><p>تم تصميم <strong>فيلم Matte PET - YG/YGD</strong> لتلبية أعلى معايير الصناعة للتغليف المرن والتطبيقات الوظيفية. باستخدام عمليات التصنيع المتقدمة، توفر هذه المادة أداءً استثنائيًا مصممًا لتلبية الاحتياجات المتخصصة.</p><h3>الخصائص الرئيسية</h3><ul>
    <li><strong>الميزة الأساسية:</strong> خيارات علاج كورونا</li><li><strong>التطبيق:</strong> عملية تصنيع خاصة</li><li><strong>المواصفات الأصلية:</strong> فيلم أصلي غير لامع</li><li><strong>ضمان الجودة:</strong> تم تصنيعه بدقة لضمان سماكة موحدة وخصائص حاجز ممتازة وقوة ميكانيكية فائقة.</li></ul>

  <h3>لماذا تختار أفلامنا؟</h3><p>سواء كنت تحتاج إلى خصائص عالية العوائق لحفظ الأغذية، أو جماليات معدنية محددة لتعزيز العلامة التجارية، أو مواد أحادية صديقة للبيئة لتحقيق أهداف الاستدامة، فإن سلسلة أفلامنا توفر حلاً موثوقًا وفعالاً من حيث التكلفة وقابل للتخصيص بدرجة كبيرة. تتوافق المادة مع عمليات التحويل المختلفة بما في ذلك الطباعة والتصفيح وصنع الأكياس.</p></div>

<div class = "product-detail-images" style = "الهامش العلوي: 40 بكسل؛ العرض: مرن؛ الاتجاه المرن: عمود؛ الفجوة: 20 بكسل؛">
  <h3 style ="margin-bottom: 20px;font-size: 24px;font-weight:old;">معرض المنتجات</h3><img src="/products/specialty-functional-films/matte-pet-film-yg-ygd/1.png" alt="فيلم PET غير لامع - YG/YGD" style="width: 100%; الحد الأقصى للعرض: 800px; الارتفاع: تلقائي; نصف قطر الحدود: 8px; ظل الصندوق: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', 0, '2026-05-07T13:22:26.429Z', '2026-06-18T03:08:30.649Z');
