INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmovin2ia0021tmrgxkyziqtd', 'Hot Stamping / Thermal Transfer PET Film - PET-HP', 'Película PET de estampado en caliente/transferencia térmica - PET-HP', 'فيلم PET بالختم الساخن / النقل الحراري - PET-HP', 'hot-stamping-thermal-transfer-pet-film', NULL, 'Película PET de estampado en caliente/transferencia térmica - PET-HP', 'فيلم PET بالختم الساخن / النقل الحراري - PET-HP', NULL, 'Película PET de estampado en caliente/transferencia térmica - PET-HP', 'فيلم PET بالختم الساخن / النقل الحراري - PET-HP', 'cmovii66i0003tmm4zk4s7tvy', '/products/specialty-functional-films/hot-stamping-thermal-transfer-pet-film-pet-hp/1.png', '["/products/specialty-functional-films/hot-stamping-thermal-transfer-pet-film-pet-hp/1.png","/products/specialty-functional-films/hot-stamping-thermal-transfer-pet-film-pet-hp/2.jpeg","/products/specialty-functional-films/hot-stamping-thermal-transfer-pet-film-pet-hp/3.jpeg","/products/specialty-functional-films/hot-stamping-thermal-transfer-pet-film-pet-hp/4.jpeg"]', '["Low Heat Shrinkage","Reusable & Good Peeling"]', '["Baja contracción por calor","Reutilizable y buen pelado."]', '["انكماش الحرارة المنخفضة","قابلة لإعادة الاستخدام وتقشير جيد"]', '<div class="product-detailed-description">
  <h3>Product Overview</h3>
  <p>The <strong>Hot Stamping / Thermal Transfer PET Film - PET-HP</strong> is engineered to meet the highest industry standards for flexible packaging and functional applications. Utilizing advanced manufacturing processes, this material delivers exceptional performance tailored for specialized needs.</p>
  
  <h3>Key Characteristics</h3>
  <ul>
    <li><strong>Core Advantage:</strong> Low Heat Shrinkage</li>
    <li><strong>Application:</strong> Reusable & Good Peeling</li>
    <li><strong>Original Spec:</strong> 烫金膜热转移聚酯基膜PET-HP</li>
    <li><strong>Quality Assurance:</strong> Manufactured with precision to ensure uniform thickness, excellent barrier properties, and superior mechanical strength.</li>
  </ul>

  <h3>Why Choose Our Films?</h3>
  <p>Whether you require high-barrier properties for food preservation, specific metallic aesthetics for brand enhancement, or eco-friendly mono-materials to meet sustainability goals, our film series provides a reliable, cost-effective, and highly customizable solution. The material is compatible with various conversion processes including printing, lamination, and pouch making.</p>
</div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: column; gap: 20px;">
