  <img src="/products/specialty-functional-films/matte-pet-film-pet/2.jpeg" alt="Matte PET Film - PET" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
