INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmovin3bw002ltmrgx3u5wcit', 'Biodegradable PLA-AlOx Film - PLA-AlOx', 'Película biodegradable PLA-AlOx - PLA-AlOx', 'فيلم PLA-AlOx القابل للتحلل الحيوي - PLA-AlOx', 'biodegradable-pla-alox-film-pla-alox', NULL, 'Película biodegradable PLA-AlOx - PLA-AlOx', 'فيلم PLA-AlOx القابل للتحلل الحيوي - PLA-AlOx', NULL, 'Película biodegradable PLA-AlOx - PLA-AlOx', 'فيلم PLA-AlOx القابل للتحلل الحيوي - PLA-AlOx', 'cmovii68y0004tmm4qtfet8ep', '/products/recyclable-mono-materials/biodegradable-pla-alox-film-pla-alox/1.jpg', '["/products/recyclable-mono-materials/biodegradable-pla-alox-film-pla-alox/1.jpg"]', '["100% Biodegradable (CO2 & Water)","Eco-Friendly Material"]', '["100% biodegradable (CO2 y agua)","Materiales ecológicos"]', '["قابل للتحلل البيولوجي بنسبة 100% (ثاني أكسيد الكربون والماء)","مواد صديقة للبيئة"]', '<div class="product-detailed-description">
  <h3>Product Overview</h3>
  <p>The <strong>Biodegradable PLA-AlOx Film - PLA-AlOx</strong> is engineered to meet the highest industry standards for flexible packaging and functional applications. Utilizing advanced manufacturing processes, this material delivers exceptional performance tailored for specialized needs.</p>
  
  <h3>Key Characteristics</h3>
  <ul>
    <li><strong>Core Advantage:</strong> 100% Biodegradable (CO2 & Water)</li>
    <li><strong>Application:</strong> Eco-Friendly Material</li>
    <li><strong>Original Spec:</strong> 生物可降解材料——聚乳酸氧化铝膜 PLA-AlOx</li>
    <li><strong>Quality Assurance:</strong> Manufactured with precision to ensure uniform thickness, excellent barrier properties, and superior mechanical strength.</li>
  </ul>

  <h3>Why Choose Our Films?</h3>
  <p>Whether you require high-barrier properties for food preservation, specific metallic aesthetics for brand enhancement, or eco-friendly mono-materials to meet sustainability goals, our film series provides a reliable, cost-effective, and highly customizable solution. The material is compatible with various conversion processes including printing, lamination, and pouch making.</p>
</div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: column; gap: 20px;">
  <h3 style="margin-bottom: 20px; font-size: 24px; font-weight: bold;">Product Gallery</h3>
  <img src="/products/recyclable-mono-materials/biodegradable-pla-alox-film-pla-alox/1.jpg" alt="Biodegradable PLA-AlOx Film - PLA-AlOx" style="width: 100%; max-width: 800px; height: auto; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', '<div class="descripción-detallada-del-producto">
  <h3>Descripción general del producto</h3><p>La <strong>Película PLA-AlOx biodegradable - PLA-AlOx</strong> está diseñada para cumplir con los más altos estándares de la industria para embalajes flexibles y aplicaciones funcionales. Utilizando procesos de fabricación avanzados, este material ofrece un rendimiento excepcional adaptado a necesidades especializadas.</p><h3>Características clave</h3><ul>
    <li><strong>Ventaja principal:</strong> 100% biodegradable (CO2 y agua)</li><li><strong>Aplicación:</strong> Material ecológico</li><li><strong>Especificaciones originales:</strong> Material biodegradable: membrana de óxido de aluminio de ácido poliláctico PLA-AlOx</li><li><strong>Garantía de calidad:</strong> Fabricado con precisión para garantizar un espesor uniforme, excelentes propiedades de barrera y una resistencia mecánica superior.</li></ul>

  <h3>¿Por qué elegir nuestras películas?</h3><p>Ya sea que necesite propiedades de alta barrera para la conservación de alimentos, una estética metálica específica para mejorar la marca o monomateriales ecológicos para cumplir los objetivos de sostenibilidad, nuestra serie de películas proporciona una solución confiable, rentable y altamente personalizable. El material es compatible con varios procesos de conversión, incluidos la impresión, la laminación y la fabricación de bolsas.</p></div>

<div class="product-detail-images" style="margin-top: 40px; display: flex; flex-direction: columna; espacio: 20px;">
  <h3 style="margin-bottom: 20px; font-size: 24px; font-weight: negrita;">Galería de productos</h3><img src="/products/recyclable-mono-materials/biodegradable-pla-alox-film-pla-alox/1.jpg" alt="Película PLA-AlOx biodegradable - PLA-AlOx" style="ancho: 100%; ancho máximo: 800px; alto: automático; radio del borde: 8px; sombra del cuadro: 0 4px 6px rgba(0,0,0,0.1);" />
</div>', '<div class="product-detailed-description">
  <h3>نظرة عامة على المنتج</h3><p>تم تصميم <strong>فيلم PLA-AlOx القابل للتحلل بيولوجيًا - PLA-AlOx</strong> لتلبية أعلى معايير الصناعة للتغليف المرن والتطبيقات الوظيفية. باستخدام عمليات التصنيع المتقدمة، توفر هذه المادة أداءً استثنائيًا مصممًا لتلبية الاحتياجات المتخصصة.</p><h3>الخصائص الرئيسية</h3><ul>
    <li><strong>الميزة الأساسية:</strong> قابل للتحلل البيولوجي بنسبة 100% (ثاني أكسيد الكربون والماء)</li><li><strong>التطبيق:</strong> مادة صديقة للبيئة</li><li><strong>المواصفات الأصلية:</strong> مادة قابلة للتحلل الحيوي - غشاء أكسيد الألومنيوم متعدد حمض اللبنيك PLA-AlOx</li><li><strong>ضمان الجودة:</strong> تم تصنيعه بدقة لضمان سماكة موحدة وخصائص حاجز ممتازة وقوة ميكانيكية فائقة.</li></ul>

  <h3>لماذا تختار أفلامنا؟</h3><p>سواء كنت تحتاج إلى خصائص عالية العوائق لحفظ الأغذية، أو جماليات معدنية محددة لتعزيز العلامة التجارية، أو مواد أحادية صديقة للبيئة لتحقيق أهداف الاستدامة، فإن سلسلة أفلامنا توفر حلاً موثوقًا وفعالاً من حيث التكلفة وقابل للتخصيص بدرجة كبيرة. تتوافق المادة مع عمليات التحويل المختلفة بما في ذلك الطباعة والتصفيح وصنع الأكياس.</p></div>

<div class = "product-detail-images" style = "الهامش العلوي: 40 بكسل؛ العرض: مرن؛ الاتجاه المرن: عمود؛ الفجوة: 20 بكسل؛">
