INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmqizhi8y0001tmi4jamle2cf', 'Moisture Barrier Packaging Bag', 'Bolsa de embalaje con barrera contra la humedad', 'كيس التغليف حاجز الرطوبة', 'moisture-barrier-packaging-bag', 'Moisture Barrier Packaging Bag | HLT PACK', 'Bolsa de embalaje con barrera contra la humedad | PAQUETE HLT', 'كيس التغليف حاجز الرطوبة | حزمة HLT', 'High quality moisture barrier packaging bag customized for your brand.', 'Bolsa de embalaje con barrera contra la humedad de alta calidad personalizada para su marca.', 'حقيبة تغليف حاجز الرطوبة عالية الجودة مخصصة لعلامتك التجارية.', 'cmqj57o8k0009tmq4xeaiircd', '/products/ziplock-bags/moisture-barrier-packaging-bag/1.png', '["/products/ziplock-bags/moisture-barrier-packaging-bag/1.png","/products/ziplock-bags/moisture-barrier-packaging-bag/2.png","/products/ziplock-bags/moisture-barrier-packaging-bag/3.png","/products/ziplock-bags/moisture-barrier-packaging-bag/4.png","/products/ziplock-bags/moisture-barrier-packaging-bag/5.png"]', '["防静电防潮袋","Moisture Barrier Packaging Bag","ESD & Moisture Protection","High Shielding Properties","Resealable Zipper Lock"]', '["Bolsa antiestática a prueba de humedad.","Bolsa de embalaje con barrera contra la humedad","ESD y protección contra la humedad","Propiedades de alto blindaje","Cierre de cremallera resellable."]', '["حقيبة مقاومة للرطوبة ومضادة للكهرباء الساكنة","كيس التغليف حاجز الرطوبة","حماية البيئة والتنمية المستدامة والرطوبة","خصائص التدريع العالية","قفل بسحاب قابل للإغلاق"]', '<p><strong>Moisture Barrier Packaging Bag</strong> manufactured by HLT PACK. We offer high-quality, custom-printed packaging solutions tailored to your brand''s needs.</p>', '<p><strong>Bolsa de Envasado Barrera de Humedad</strong> fabricada por HLT PACK. Ofrecemos soluciones de embalaje impresas personalizadas y de alta calidad adaptadas a las necesidades de su marca.</p>', '<p><strong>كيس تغليف حاجز الرطوبة</strong> تم تصنيعه بواسطة HLT PACK. نحن نقدم حلول تغليف مطبوعة عالية الجودة ومصممة خصيصًا لتلبية احتياجات علامتك التجارية.</p>', 0, '2026-06-18T04:12:25.322Z', '2026-06-18T06:52:45.782Z');

