INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oku0000tmnsr1lj4wla', 'How to Choose the Right Food Packaging Bag?', '¿Cómo elegir la bolsa adecuada para envasado de alimentos?', 'كيفية اختيار كيس تغليف المواد الغذائية المناسب؟', 'how-to-choose-right-food-packaging-bag', 'How to Choose the Right Food Packaging Bag?', '¿Cómo elegir la bolsa adecuada para envasado de alimentos?', 'كيفية اختيار كيس تغليف المواد الغذائية المناسب؟', 'Choosing the right food packaging bag is crucial for preserving product quality, extending shelf life, and attracting consumers. This guide covers material selection, barrier properties, and printing options.', 'Elegir la bolsa de envasado de alimentos adecuada es fundamental para preservar la calidad del producto, prolongar la vida útil y atraer a los consumidores. Esta guía cubre la selección de materiales, propiedades de barrera y opciones de impresión.', 'يعد اختيار كيس تغليف المواد الغذائية المناسب أمرًا بالغ الأهمية للحفاظ على جودة المنتج وإطالة العمر الافتراضي وجذب المستهلكين. يغطي هذا الدليل اختيار المواد وخصائص الحاجز وخيارات الطباعة.', 'Choosing the right food packaging bag is crucial for preserving product quality, extending shelf life, and attracting consumers. This guide covers material selection, barrier properties, and printing options.', 'Elegir la bolsa de envasado de alimentos adecuada es fundamental para preservar la calidad del producto, prolongar la vida útil y atraer a los consumidores. Esta guía cubre la selección de materiales, propiedades de barrera y opciones de impresión.', 'يعد اختيار كيس تغليف المواد الغذائية المناسب أمرًا بالغ الأهمية للحفاظ على جودة المنتج وإطالة العمر الافتراضي وجذب المستهلكين. يغطي هذا الدليل اختيار المواد وخصائص الحاجز وخيارات الطباعة.', '<p>When selecting food packaging bags, consider the following factors: 1. Material safety (must be food-grade), 2. Barrier requirements (oxygen and moisture resistance), 3. Physical strength (puncture resistance), 4. Convenience (zippers, tear notches). At HLT PACK, we provide customized solutions based on your specific product needs.</p>', '<p>Al seleccionar bolsas para empaquetar alimentos, considere los siguientes factores: 1. Seguridad del material (debe ser de calidad alimentaria), 2. Requisitos de barrera (resistencia al oxígeno y a la humedad), 3. Resistencia física (resistencia a perforaciones), 4. Comodidad (cremalleras, muescas de desgarro). En HLT PACK, brindamos soluciones personalizadas basadas en las necesidades específicas de su producto.</p>', '<p>عند اختيار أكياس تغليف المواد الغذائية، ضع في اعتبارك العوامل التالية: 1. سلامة المواد (يجب أن تكون من الدرجة الغذائية)، 2. متطلبات الحاجز (مقاومة الأكسجين والرطوبة)، 3. القوة البدنية (مقاومة الثقب)، 4. الراحة (السحابات، الشقوق المسيل للدموع). في HLT PACK، نقدم حلولًا مخصصة بناءً على احتياجات المنتج المحددة الخاصة بك.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.11.20', '/images/factory/印刷车间/10001.png', '2026-04-29T13:50:46.638Z', '2026-05-04T12:08:49.414Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ong0001tmnsozp8007n', 'What are the Advantages of Transparent Plastic Bags?', '¿Cuáles son las ventajas de las bolsas de plástico transparentes?', 'ما هي مزايا الأكياس البلاستيكية الشفافة؟', 'advantages-of-transparent-plastic-bags', 'What are the Advantages of Transparent Plastic Bags?', '¿Cuáles son las ventajas de las bolsas de plástico transparentes?', 'ما هي مزايا الأكياس البلاستيكية الشفافة؟', 'Transparent plastic bags offer high visibility, allowing consumers to see the product inside. This builds trust and enhances the visual appeal of fresh produce and retail goods.', 'Las bolsas de plástico transparentes ofrecen alta visibilidad, permitiendo a los consumidores ver el producto en su interior. Esto genera confianza y mejora el atractivo visual de los productos frescos y los productos minoristas.', 'توفر الأكياس البلاستيكية الشفافة رؤية عالية، مما يسمح للمستهلكين برؤية المنتج من الداخل. وهذا يبني الثقة ويعزز الجاذبية البصرية للمنتجات الطازجة وسلع البيع بالتجزئة.', 'Transparent plastic bags offer high visibility, allowing consumers to see the product inside. This builds trust and enhances the visual appeal of fresh produce and retail goods.', 'Las bolsas de plástico transparentes ofrecen alta visibilidad, permitiendo a los consumidores ver el producto en su interior. Esto genera confianza y mejora el atractivo visual de los productos frescos y los productos minoristas.', 'توفر الأكياس البلاستيكية الشفافة رؤية عالية، مما يسمح للمستهلكين برؤية المنتج من الداخل. وهذا يبني الثقة ويعزز الجاذبية البصرية للمنتجات الطازجة وسلع البيع بالتجزئة.', '<p>Transparent packaging stands out by offering complete visibility. It is widely used in the fresh food, hardware, and cosmetics industries. Our high-clarity OPP and PE bags ensure your products look their best on the shelf while providing excellent moisture protection.</p>', '<p>El packaging transparente destaca por ofrecer una visibilidad completa. Se utiliza ampliamente en las industrias de alimentos frescos, ferretería y cosmética. Nuestras bolsas de OPP y PE de alta claridad garantizan que sus productos luzcan lo mejor posible en el estante y, al mismo tiempo, brindan una excelente protección contra la humedad.</p>', '<p>تتميز العبوة الشفافة بتوفير رؤية كاملة. يتم استخدامه على نطاق واسع في صناعات المواد الغذائية الطازجة والأجهزة ومستحضرات التجميل. تضمن أكياس OPP وPE عالية الوضوح أن تبدو منتجاتك في أفضل حالاتها على الرف مع توفير حماية ممتازة من الرطوبة.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.11.15', '/images/factory/印刷车间/10002.png', '2026-04-29T13:50:46.732Z', '2026-05-04T12:08:49.529Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44opi0002tmnszc7l11hz', 'The Benefits of Eco-Friendly Packaging Bags', 'Los beneficios de las bolsas de embalaje ecológicas', 'فوائد أكياس التغليف الصديقة للبيئة', 'benefits-of-eco-friendly-packaging', 'The Benefits of Eco-Friendly Packaging Bags', 'Los beneficios de las bolsas de embalaje ecológicas', 'فوائد أكياس التغليف الصديقة للبيئة', 'Eco-friendly packaging is becoming the new standard. Discover how biodegradable and recyclable materials can reduce your carbon footprint and appeal to modern consumers.', 'Los envases ecológicos se están convirtiendo en el nuevo estándar. Descubra cómo los materiales biodegradables y reciclables pueden reducir su huella de carbono y atraer a los consumidores modernos.', 'أصبح التغليف الصديق للبيئة هو المعيار الجديد. اكتشف كيف يمكن للمواد القابلة للتحلل الحيوي وإعادة التدوير أن تقلل من انبعاثات الكربون وتجذب المستهلكين المعاصرين.', 'Eco-friendly packaging is becoming the new standard. Discover how biodegradable and recyclable materials can reduce your carbon footprint and appeal to modern consumers.', 'Los envases ecológicos se están convirtiendo en el nuevo estándar. Descubra cómo los materiales biodegradables y reciclables pueden reducir su huella de carbono y atraer a los consumidores modernos.', 'أصبح التغليف الصديق للبيئة هو المعيار الجديد. اكتشف كيف يمكن للمواد القابلة للتحلل الحيوي وإعادة التدوير أن تقلل من انبعاثات الكربون وتجذب المستهلكين المعاصرين.', '<p>Sustainable packaging helps reduce environmental impact and aligns with global green initiatives. HLT PACK offers a range of recyclable mono-material pouches and compostable films that deliver the same high-barrier performance as traditional plastics.</p>', '<p>Los envases sostenibles ayudan a reducir el impacto ambiental y se alinean con las iniciativas ecológicas globales. HLT PACK ofrece una gama de bolsas monomaterial reciclables y películas compostables que ofrecen el mismo rendimiento de alta barrera que los plásticos tradicionales.</p>', '<p>يساعد التغليف المستدام على تقليل التأثير البيئي ويتوافق مع المبادرات الخضراء العالمية. تقدم HLT PACK مجموعة من الأكياس أحادية المادة القابلة لإعادة التدوير والأغشية القابلة للتحلل والتي توفر نفس الأداء العالي الحاجز الذي توفره المواد البلاستيكية التقليدية.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.11.10', '/images/factory/印刷车间/10003.png', '2026-04-29T13:50:46.806Z', '2026-05-04T12:08:49.749Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ork0003tmns2v7nhcvj', 'Understanding Aluminum Foil Bags', 'Entendiendo las bolsas de papel de aluminio', 'فهم أكياس رقائق الألومنيوم', 'understanding-aluminum-foil-bags', 'Understanding Aluminum Foil Bags', 'Entendiendo las bolsas de papel de aluminio', 'فهم أكياس رقائق الألومنيوم', 'Aluminum foil bags provide the ultimate barrier against light, oxygen, and moisture. Learn why they are the top choice for coffee, tea, and sensitive electronics.', 'Las bolsas de papel de aluminio proporcionan la barrera definitiva contra la luz, el oxígeno y la humedad. Descubra por qué son la mejor opción para café, té y aparatos electrónicos sensibles.', 'توفر أكياس رقائق الألومنيوم الحاجز النهائي ضد الضوء والأكسجين والرطوبة. تعرف على سبب كونها الخيار الأفضل للقهوة والشاي والإلكترونيات الحساسة.', 'Aluminum foil bags provide the ultimate barrier against light, oxygen, and moisture. Learn why they are the top choice for coffee, tea, and sensitive electronics.', 'Las bolsas de papel de aluminio proporcionan la barrera definitiva contra la luz, el oxígeno y la humedad. Descubra por qué son la mejor opción para café, té y aparatos electrónicos sensibles.', 'توفر أكياس رقائق الألومنيوم الحاجز النهائي ضد الضوء والأكسجين والرطوبة. تعرف على سبب كونها الخيار الأفضل للقهوة والشاي والإلكترونيات الحساسة.', '<p>Featuring a multi-layer composite structure, aluminum foil bags completely block out UV light and oxygen. They are essential for extending the shelf life of roasted coffee beans, premium teas, and pharmaceutical products.</p>', '<p>Con una estructura compuesta de múltiples capas, las bolsas de papel de aluminio bloquean completamente la luz ultravioleta y el oxígeno. Son esenciales para prolongar la vida útil de los granos de café tostados, tés premium y productos farmacéuticos.</p>', '<p>تتميز أكياس رقائق الألومنيوم بهيكل مركب متعدد الطبقات، مما يمنع الأشعة فوق البنفسجية والأكسجين تمامًا. فهي ضرورية لإطالة العمر الافتراضي لحبوب القهوة المحمصة، والشاي الفاخر، والمنتجات الصيدلانية.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.11.05', '/images/factory/印刷车间/10004.png', '2026-04-29T13:50:46.880Z', '2026-05-04T12:08:49.903Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oto0004tmnsd4snwvp3', 'What is a Retort Pouch?', '¿Qué es una bolsa de retorta?', 'ما هي الحقيبة المعوجة؟', 'what-is-a-retort-pouch', 'What is a Retort Pouch?', '¿Qué es una bolsa de retorta?', 'ما هي الحقيبة المعوجة؟', 'Retort pouches are designed to withstand high temperatures during sterilization. They are lightweight alternatives to cans and glass jars for ready-to-eat meals.', 'Las bolsas de retorta están diseñadas para soportar altas temperaturas durante la esterilización. Son alternativas ligeras a las latas y tarros de cristal para comidas preparadas.', 'تم تصميم أكياس المعوجة لتحمل درجات الحرارة المرتفعة أثناء التعقيم. إنها بدائل خفيفة الوزن للعلب والجرار الزجاجية للوجبات الجاهزة للأكل.', 'Retort pouches are designed to withstand high temperatures during sterilization. They are lightweight alternatives to cans and glass jars for ready-to-eat meals.', 'Las bolsas de retorta están diseñadas para soportar altas temperaturas durante la esterilización. Son alternativas ligeras a las latas y tarros de cristal para comidas preparadas.', 'تم تصميم أكياس المعوجة لتحمل درجات الحرارة المرتفعة أثناء التعقيم. إنها بدائل خفيفة الوزن للعلب والجرار الزجاجية للوجبات الجاهزة للأكل.', '<p>Retort pouches are made from specialized laminates that can survive temperatures up to 121°C (250°F). They offer a long shelf life for liquid foods, curries, and pet food without requiring refrigeration.</p>', '<p>Las bolsas de retorta están hechas de laminados especializados que pueden resistir temperaturas de hasta 121 °C (250 °F). Ofrecen una larga vida útil para alimentos líquidos, curry y alimentos para mascotas sin necesidad de refrigeración.</p>', '<p>تُصنع أكياس المعوجة من شرائح متخصصة يمكنها تحمل درجات حرارة تصل إلى 121 درجة مئوية (250 درجة فهرنهايت). فهي توفر فترة صلاحية طويلة للأطعمة السائلة والكاري وأغذية الحيوانات الأليفة دون الحاجة إلى التبريد.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.10.28', '/images/factory/印刷车间/10005.png', '2026-04-29T13:50:46.956Z', '2026-05-04T12:08:50.079Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ow90005tmnsqr63crnp', 'Custom Printed Pouch Design Guidelines', 'Pautas de diseño de bolsas impresas personalizadas', 'إرشادات تصميم الحقيبة المطبوعة المخصصة', 'custom-printed-pouch-design-guidelines', 'Custom Printed Pouch Design Guidelines', 'Pautas de diseño de bolsas impresas personalizadas', 'إرشادات تصميم الحقيبة المطبوعة المخصصة', 'A great design makes your product pop. Learn the basics of preparing your artwork for rotogravure printing to ensure vibrant colors and sharp details.', 'Un gran diseño hace que su producto destaque. Aprenda los conceptos básicos de la preparación de su obra de arte para la impresión en huecograbado para garantizar colores vibrantes y detalles nítidos.', 'التصميم الرائع يجعل منتجك بارزًا. تعرّف على أساسيات إعداد عملك الفني للطباعة المطبعة لضمان الحصول على ألوان نابضة بالحياة وتفاصيل دقيقة.', 'A great design makes your product pop. Learn the basics of preparing your artwork for rotogravure printing to ensure vibrant colors and sharp details.', 'Un gran diseño hace que su producto destaque. Aprenda los conceptos básicos de la preparación de su obra de arte para la impresión en huecograbado para garantizar colores vibrantes y detalles nítidos.', 'التصميم الرائع يجعل منتجك بارزًا. تعرّف على أساسيات إعداد عملك الفني للطباعة المطبعة لضمان الحصول على ألوان نابضة بالحياة وتفاصيل دقيقة.', '<p>To achieve the best printing results, provide vector artwork in CMYK color mode. Pay attention to bleed areas and avoid placing critical text near the sealing edges. Our prepress team is always available to help optimize your designs.</p>', '<p>Para lograr los mejores resultados de impresión, proporcione ilustraciones vectoriales en modo de color CMYK. Preste atención a las áreas de sangrado y evite colocar texto crítico cerca de los bordes de sellado. Nuestro equipo de preimpresión está siempre disponible para ayudarle a optimizar sus diseños.</p>', '<p>للحصول على أفضل نتائج الطباعة، قم بتوفير عمل فني متجه في وضع ألوان CMYK. انتبه إلى مناطق التسييل وتجنب وضع النص المهم بالقرب من حواف الختم. فريق ما قبل الطباعة لدينا متاح دائمًا للمساعدة في تحسين تصميماتك.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.10.20', '/images/factory/制袋车间/10001.png', '2026-04-29T13:50:47.049Z', '2026-05-04T12:08:50.279Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oya0006tmnsdgknsaqq', 'Vacuum Bags: Extending Shelf Life', 'Bolsas de vacío: prolongación de la vida útil', 'أكياس الفراغ: تمديد مدة الصلاحية', 'vacuum-bags-extending-shelf-life', 'Vacuum Bags: Extending Shelf Life', 'Bolsas de vacío: prolongación de la vida útil', 'أكياس الفراغ: تمديد مدة الصلاحية', 'By removing air from the package, vacuum bags significantly slow down the growth of bacteria and fungi, keeping meat, cheese, and nuts fresh for longer.', 'Al eliminar el aire del paquete, las bolsas de vacío ralentizan significativamente el crecimiento de bacterias y hongos, manteniendo frescos la carne, el queso y las nueces por más tiempo.', 'من خلال إزالة الهواء من العبوة، تعمل أكياس التفريغ على إبطاء نمو البكتيريا والفطريات بشكل كبير، مما يحافظ على اللحوم والجبن والمكسرات طازجة لفترة أطول.', 'By removing air from the package, vacuum bags significantly slow down the growth of bacteria and fungi, keeping meat, cheese, and nuts fresh for longer.', 'Al eliminar el aire del paquete, las bolsas de vacío ralentizan significativamente el crecimiento de bacterias y hongos, manteniendo frescos la carne, el queso y las nueces por más tiempo.', 'من خلال إزالة الهواء من العبوة، تعمل أكياس التفريغ على إبطاء نمو البكتيريا والفطريات بشكل كبير، مما يحافظ على اللحوم والجبن والمكسرات طازجة لفترة أطول.', '<p>Vacuum packaging is a proven method for food preservation. Our heavy-duty vacuum bags are highly puncture-resistant, ensuring the vacuum seal remains intact during transportation and storage.</p>', '<p>El envasado al vacío es un método probado para la conservación de alimentos. Nuestras bolsas de vacío de alta resistencia son altamente resistentes a las perforaciones, lo que garantiza que el sello de vacío permanezca intacto durante el transporte y el almacenamiento.</p>', '<p>تعتبر التعبئة والتغليف المفرغ من الهواء طريقة مجربة لحفظ الأغذية. تتميز أكياس التفريغ شديدة التحمل لدينا بمقاومة عالية للثقب، مما يضمن بقاء ختم التفريغ سليمًا أثناء النقل والتخزين.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.10.12', '/images/factory/制袋车间/10002.png', '2026-04-29T13:50:47.123Z', '2026-05-04T12:08:50.437Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p050007tmns37j2v64x', 'The Rise of Stand-Up Pouches with Zippers', 'El auge de las bolsas verticales con cremalleras', 'صعود الحقائب الوقوف مع السوستة', 'rise-of-stand-up-pouches-with-zippers', 'The Rise of Stand-Up Pouches with Zippers', 'El auge de las bolsas verticales con cremalleras', 'صعود الحقائب الوقوف مع السوستة', 'Stand-up pouches dominate the retail space due to their convenience and shelf presence. The addition of a resealable zipper adds immense value for consumers.', 'Las bolsas stand-up dominan el espacio minorista debido a su conveniencia y presencia en los estantes. La adición de una cremallera resellable añade un valor inmenso para los consumidores.', 'تهيمن الحقائب القائمة على مساحة البيع بالتجزئة نظرًا لراحتها ووجودها على الرف. تضيف إضافة السحاب القابل للإغلاق قيمة هائلة للمستهلكين.', 'Stand-up pouches dominate the retail space due to their convenience and shelf presence. The addition of a resealable zipper adds immense value for consumers.', 'Las bolsas stand-up dominan el espacio minorista debido a su conveniencia y presencia en los estantes. La adición de una cremallera resellable añade un valor inmenso para los consumidores.', 'تهيمن الحقائب القائمة على مساحة البيع بالتجزئة نظرًا لراحتها ووجودها على الرف. تضيف إضافة السحاب القابل للإغلاق قيمة هائلة للمستهلكين.', '<p>Offering a large billboard area for branding, stand-up pouches are perfect for snacks, pet food, and powders. The built-in bottom gusset allows the bag to stand upright, while the zipper ensures the contents stay fresh after opening.</p>', '<p>Las bolsas verticales, que ofrecen una gran área de vallas publicitarias para la marca, son perfectas para bocadillos, comida para mascotas y polvos. El refuerzo inferior incorporado permite que la bolsa se mantenga en posición vertical, mientras que la cremallera garantiza que el contenido se mantenga fresco después de abrirlo.</p>', '<p>توفر مساحة كبيرة للوحة الإعلانات للعلامات التجارية، وتعد الأكياس القائمة مثالية للوجبات الخفيفة وأطعمة الحيوانات الأليفة والمساحيق. يسمح الجزء السفلي المدمج للحقيبة بالوقوف في وضع مستقيم، بينما يضمن السحاب بقاء المحتويات طازجة بعد الفتح.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.10.05', '/images/factory/制袋车间/10003.png', '2026-04-29T13:50:47.189Z', '2026-05-04T12:08:50.612Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p200008tmns6qtgehut', 'How to Measure a Packaging Bag Correctly?', '¿Cómo medir correctamente una bolsa de embalaje?', 'كيفية قياس كيس التغليف بشكل صحيح؟', 'how-to-measure-packaging-bag', 'How to Measure a Packaging Bag Correctly?', '¿Cómo medir correctamente una bolsa de embalaje?', 'كيفية قياس كيس التغليف بشكل صحيح؟', 'Accurate measurements are the first step to creating the perfect custom bag. Learn how to measure width, length, and gussets properly.', 'Las medidas precisas son el primer paso para crear el bolso personalizado perfecto. Aprenda a medir correctamente el ancho, el largo y los refuerzos.', 'القياسات الدقيقة هي الخطوة الأولى لإنشاء الحقيبة المخصصة المثالية. تعرف على كيفية قياس العرض والطول وألواح التقوية بشكل صحيح.', 'Accurate measurements are the first step to creating the perfect custom bag. Learn how to measure width, length, and gussets properly.', 'Las medidas precisas son el primer paso para crear el bolso personalizado perfecto. Aprenda a medir correctamente el ancho, el largo y los refuerzos.', 'القياسات الدقيقة هي الخطوة الأولى لإنشاء الحقيبة المخصصة المثالية. تعرف على كيفية قياس العرض والطول وألواح التقوية بشكل صحيح.', '<p>When specifying bag dimensions, always provide the Outer Dimensions (OD). For stand-up pouches, measure Width x Height + Bottom Gusset. Remember to account for the seal width and the volume of the product you intend to fill.</p>', '<p>Al especificar las dimensiones de la bolsa, proporcione siempre las dimensiones exteriores (OD). Para bolsas verticales, mida Ancho x Alto + Refuerzo inferior. Recuerda tener en cuenta el ancho del sello y el volumen del producto que pretendes llenar.</p>', '<p>عند تحديد أبعاد الحقيبة، قم دائمًا بتوفير الأبعاد الخارجية (OD). بالنسبة للحقائب القائمة، قم بقياس العرض × الارتفاع + لوح التقوية السفلي. تذكر أن تأخذ في الاعتبار عرض الختم وحجم المنتج الذي تنوي تعبئته.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.09.28', '/images/factory/制袋车间/10004.png', '2026-04-29T13:50:47.256Z', '2026-05-04T12:08:50.770Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p3u0009tmnsw8ae3ar9', 'Why Choose Solvent-Free Lamination?', '¿Por qué elegir la laminación sin disolventes?', 'لماذا تختار التصفيح الخالي من المذيبات؟', 'why-choose-solvent-free-lamination', 'Why Choose Solvent-Free Lamination?', '¿Por qué elegir la laminación sin disolventes?', 'لماذا تختار التصفيح الخالي من المذيبات؟', 'Solvent-free lamination is safer for the environment and food products. It eliminates the risk of solvent residue and VOC emissions.', 'La laminación sin disolventes es más segura para el medio ambiente y los productos alimenticios. Elimina el riesgo de residuos de disolventes y emisiones de COV.', 'التصفيح الخالي من المذيبات أكثر أمانًا للبيئة والمنتجات الغذائية. إنه يزيل خطر بقايا المذيبات وانبعاثات المركبات العضوية المتطايرة.', 'Solvent-free lamination is safer for the environment and food products. It eliminates the risk of solvent residue and VOC emissions.', 'La laminación sin disolventes es más segura para el medio ambiente y los productos alimenticios. Elimina el riesgo de residuos de disolventes y emisiones de COV.', 'التصفيح الخالي من المذيبات أكثر أمانًا للبيئة والمنتجات الغذائية. إنه يزيل خطر بقايا المذيبات وانبعاثات المركبات العضوية المتطايرة.', '<p>At HLT PACK, we utilize advanced solvent-free laminators. This process uses 100% solid adhesives, curing quickly without releasing harmful emissions, making it the safest choice for food-contact packaging.</p>', '<p>En HLT PACK, utilizamos laminadoras avanzadas sin disolventes. Este proceso utiliza adhesivos 100 % sólidos, que curan rápidamente sin liberar emisiones nocivas, lo que lo convierte en la opción más segura para envases que entran en contacto con alimentos.</p>', '<p>في HLT PACK، نستخدم آلات تغليف متقدمة خالية من المذيبات. تستخدم هذه العملية مواد لاصقة صلبة بنسبة 100%، وتعالج بسرعة دون إطلاق انبعاثات ضارة، مما يجعلها الخيار الأكثر أمانًا للتغليف الملامس للأغذية.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.09.20', '/images/factory/制袋车间/10005.png', '2026-04-29T13:50:47.323Z', '2026-05-04T12:08:50.903Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p5p000atmnsxg1sf6sm', 'Spout Pouches for Liquid Packaging', 'Bolsas con pico para envasado de líquidos', 'الحقائب صنبور للتغليف السائل', 'spout-pouches-liquid-packaging', 'Spout Pouches for Liquid Packaging', 'Bolsas con pico para envasado de líquidos', 'الحقائب صنبور للتغليف السائل', 'Spout pouches offer a lightweight, unbreakable alternative to rigid bottles. They are ideal for beverages, sauces, and liquid detergents.', 'Las bolsas con boquilla ofrecen una alternativa liviana e irrompible a las botellas rígidas. Son ideales para bebidas, salsas y detergentes líquidos.', 'توفر أكياس الصنبور بديلاً خفيف الوزن وغير قابل للكسر للزجاجات الصلبة. إنها مثالية للمشروبات والصلصات والمنظفات السائلة.', 'Spout pouches offer a lightweight, unbreakable alternative to rigid bottles. They are ideal for beverages, sauces, and liquid detergents.', 'Las bolsas con boquilla ofrecen una alternativa liviana e irrompible a las botellas rígidas. Son ideales para bebidas, salsas y detergentes líquidos.', 'توفر أكياس الصنبور بديلاً خفيف الوزن وغير قابل للكسر للزجاجات الصلبة. إنها مثالية للمشروبات والصلصات والمنظفات السائلة.', '<p>Designed with leak-proof seals and easy-pour spouts, these pouches are highly convenient for on-the-go consumption. They also reduce transportation costs and plastic waste compared to traditional rigid containers.</p>', '<p>Diseñadas con sellos a prueba de fugas y picos de fácil vertido, estas bolsas son muy convenientes para consumir mientras viaja. También reducen los costes de transporte y los residuos plásticos en comparación con los contenedores rígidos tradicionales.</p>', '<p>تم تصميم هذه الأكياس بأختام مانعة للتسرب وصنبور سهلة الصب، وهي مريحة للغاية للاستهلاك أثناء التنقل. كما أنها تقلل من تكاليف النقل والنفايات البلاستيكية مقارنة بالحاويات الصلبة التقليدية.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.09.15', '/images/factory/制袋车间/10006.png', '2026-04-29T13:50:47.390Z', '2026-05-04T12:08:51.044Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p80000btmns71wruvm3', 'The Difference Between PE and PP Films', 'La diferencia entre películas de PE y PP', 'الفرق بين أفلام PE وPP', 'difference-between-pe-and-pp-films', 'The Difference Between PE and PP Films', 'La diferencia entre películas de PE y PP', 'الفرق بين أفلام PE وPP', 'Polyethylene (PE) and Polypropylene (PP) are the two most common packaging plastics. Understand their distinct properties to make the right choice.', 'El polietileno (PE) y el polipropileno (PP) son los dos plásticos de embalaje más comunes. Comprenda sus distintas propiedades para tomar la decisión correcta.', 'يعد البولي إيثيلين (PE) والبولي بروبيلين (PP) من أكثر مواد التغليف البلاستيكية شيوعًا. فهم خصائصها المميزة لاتخاذ القرار الصحيح.', 'Polyethylene (PE) and Polypropylene (PP) are the two most common packaging plastics. Understand their distinct properties to make the right choice.', 'El polietileno (PE) y el polipropileno (PP) son los dos plásticos de embalaje más comunes. Comprenda sus distintas propiedades para tomar la decisión correcta.', 'يعد البولي إيثيلين (PE) والبولي بروبيلين (PP) من أكثر مواد التغليف البلاستيكية شيوعًا. فهم خصائصها المميزة لاتخاذ القرار الصحيح.', '<p>PE is soft, flexible, and offers excellent heat-sealing properties, making it ideal for inner sealing layers. PP is stiffer, highly transparent, and provides a better moisture barrier, often used as the outer printing layer.</p>', '<p>El PE es suave, flexible y ofrece excelentes propiedades de termosellado, lo que lo hace ideal para capas de sellado internas. El PP es más rígido, muy transparente y proporciona una mejor barrera contra la humedad, a menudo utilizado como capa de impresión exterior.</p>', '<p>يمتاز البولي إيثيلين بأنه ناعم ومرن ويوفر خصائص ممتازة للختم الحراري، مما يجعله مثاليًا لطبقات الختم الداخلية. يعتبر PP أكثر صلابة، وشفافية عالية، ويوفر حاجزًا أفضل للرطوبة، وغالبًا ما يستخدم كطبقة طباعة خارجية.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.09.08', '/images/factory/制袋车间/10007.png', '2026-04-29T13:50:47.472Z', '2026-05-04T12:08:51.228Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p9v000ctmns8txyytpq', 'What is the Minimum Order Quantity (MOQ)?', '¿Cuál es la cantidad mínima de pedido (MOQ)?', 'ما هو الحد الأدنى لكمية الطلب (موك)؟', 'what-is-minimum-order-quantity', 'What is the Minimum Order Quantity (MOQ)?', '¿Cuál es la cantidad mínima de pedido (MOQ)?', 'ما هو الحد الأدنى لكمية الطلب (موك)؟', 'Understanding MOQs is essential for custom printing. We explain how printing cylinders and machine setup dictate the minimum run size.', 'Comprender las MOQ es esencial para la impresión personalizada. Explicamos cómo los cilindros de impresión y la configuración de la máquina dictan el tamaño mínimo de tirada.', 'يعد فهم MOQs أمرًا ضروريًا للطباعة المخصصة. نوضح كيف تحدد أسطوانات الطباعة وإعدادات الجهاز الحد الأدنى لحجم التشغيل.', 'Understanding MOQs is essential for custom printing. We explain how printing cylinders and machine setup dictate the minimum run size.', 'Comprender las MOQ es esencial para la impresión personalizada. Explicamos cómo los cilindros de impresión y la configuración de la máquina dictan el tamaño mínimo de tirada.', 'يعد فهم MOQs أمرًا ضروريًا للطباعة المخصصة. نوضح كيف تحدد أسطوانات الطباعة وإعدادات الجهاز الحد الأدنى لحجم التشغيل.', '<p>For custom rotogravure printing, the MOQ is typically determined by the size of the bag and the length of the master film roll (usually requiring at least 10,000 to 20,000 pieces). However, we also offer digital printing solutions for smaller test runs.</p>', '<p>Para la impresión en huecograbado personalizada, la cantidad mínima de pedido suele estar determinada por el tamaño de la bolsa y la longitud del rollo de película maestra (normalmente requiere al menos entre 10 000 y 20 000 piezas). Sin embargo, también ofrecemos soluciones de impresión digital para tiradas de prueba más pequeñas.</p>', '<p>بالنسبة للطباعة الروتوغرافية المخصصة، يتم تحديد موك عادةً حسب حجم الكيس وطول لفة الفيلم الرئيسية (عادةً ما يتطلب ما لا يقل عن 10000 إلى 20000 قطعة). ومع ذلك، فإننا نقدم أيضًا حلول الطباعة الرقمية لعمليات الاختبار الصغيرة.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.09.01', '/images/factory/制袋车间/10008.png', '2026-04-29T13:50:47.539Z', '2026-05-04T12:08:51.412Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pbp000dtmns8ut70yh1', 'Matte vs. Glossy Finish: Which is Better?', 'Acabado mate o brillante: ¿cuál es mejor?', 'ماتي مقابل لامعة: أيهما أفضل؟', 'matte-vs-glossy-finish', 'Matte vs. Glossy Finish: Which is Better?', 'Acabado mate o brillante: ¿cuál es mejor?', 'ماتي مقابل لامعة: أيهما أفضل؟', 'The finish of your packaging heavily influences brand perception. Explore the aesthetic and practical differences between matte and glossy varnishes.', 'El acabado de su embalaje influye en gran medida en la percepción de la marca. Explore las diferencias estéticas y prácticas entre barnices mate y brillantes.', 'يؤثر الانتهاء من العبوة الخاصة بك بشكل كبير على إدراك العلامة التجارية. اكتشف الاختلافات الجمالية والعملية بين الورنيش اللامع وغير اللامع.', 'The finish of your packaging heavily influences brand perception. Explore the aesthetic and practical differences between matte and glossy varnishes.', 'El acabado de su embalaje influye en gran medida en la percepción de la marca. Explore las diferencias estéticas y prácticas entre barnices mate y brillantes.', 'يؤثر الانتهاء من العبوة الخاصة بك بشكل كبير على إدراك العلامة التجارية. اكتشف الاختلافات الجمالية والعملية بين الورنيش اللامع وغير اللامع.', '<p>A glossy finish provides vibrant, eye-catching colors and a highly reflective surface. A matte finish offers a premium, understated look that feels soft to the touch and reduces glare, making text easier to read under bright lights.</p>', '<p>Un acabado brillante proporciona colores vibrantes y llamativos y una superficie altamente reflectante. Un acabado mate ofrece una apariencia premium y discreta que se siente suave al tacto y reduce el brillo, lo que hace que el texto sea más fácil de leer bajo luces brillantes.</p>', '<p>توفر اللمسة النهائية اللامعة ألوانًا نابضة بالحياة وملفتة للنظر وسطحًا عاكسًا للغاية. يوفر اللون غير اللامع مظهرًا متميزًا وبسيطًا يتميز بملمس ناعم ويقلل من الوهج، مما يجعل قراءة النص أسهل تحت الأضواء الساطعة.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.08.25', '/images/factory/制袋车间/10009.png', '2026-04-29T13:50:47.606Z', '2026-05-04T12:08:51.551Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pdk000etmnsrmzv7ckk', 'How Long Does Custom Packaging Take?', '¿Cuánto tiempo lleva el embalaje personalizado?', 'كم من الوقت يستغرق التغليف المخصص؟', 'how-long-custom-packaging-take', 'How Long Does Custom Packaging Take?', '¿Cuánto tiempo lleva el embalaje personalizado?', 'كم من الوقت يستغرق التغليف المخصص؟', 'From design approval to final delivery, we break down the typical lead times for manufacturing custom flexible packaging.', 'Desde la aprobación del diseño hasta la entrega final, desglosamos los plazos de entrega típicos para la fabricación de envases flexibles personalizados.', 'بدءًا من الموافقة على التصميم وحتى التسليم النهائي، نقوم بتفصيل المهل الزمنية النموذجية لتصنيع عبوات مرنة مخصصة.', 'From design approval to final delivery, we break down the typical lead times for manufacturing custom flexible packaging.', 'Desde la aprobación del diseño hasta la entrega final, desglosamos los plazos de entrega típicos para la fabricación de envases flexibles personalizados.', 'بدءًا من الموافقة على التصميم وحتى التسليم النهائي، نقوم بتفصيل المهل الزمنية النموذجية لتصنيع عبوات مرنة مخصصة.', '<p>The standard lead time is 15-20 days. This includes cylinder engraving (3-5 days), printing and lamination (5-7 days), curing (2-3 days), and pouch making/QC (3-5 days). Shipping times vary based on your global location.</p>', '<p>El plazo de entrega estándar es de 15 a 20 días. Esto incluye grabado de cilindros (de 3 a 5 días), impresión y laminación (de 5 a 7 días), curado (de 2 a 3 días) y fabricación de bolsas/control de calidad (de 3 a 5 días). Los tiempos de envío varían según su ubicación global.</p>', '<p>المهلة القياسية هي 15-20 يومًا. يتضمن ذلك نقش الأسطوانة (3-5 أيام)، والطباعة والتصفيح (5-7 أيام)، والمعالجة (2-3 أيام)، وصنع الأكياس/مراقبة الجودة (3-5 أيام). تختلف أوقات الشحن بناءً على موقعك العالمي.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.08.18', '/images/factory/制袋车间/10010.png', '2026-04-29T13:50:47.673Z', '2026-05-04T12:08:51.698Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pff000ftmnsw8rez72h', 'Food Grade Inks and Safety Standards', 'Tintas de calidad alimentaria y estándares de seguridad', 'الأحبار الغذائية ومعايير السلامة', 'food-grade-inks-safety-standards', 'Food Grade Inks and Safety Standards', 'Tintas de calidad alimentaria y estándares de seguridad', 'الأحبار الغذائية ومعايير السلامة', 'Not all inks are created equal. Discover why we strictly use toluene-free, heavy-metal-free inks for all our food packaging products.', 'No todas las tintas son iguales. Descubra por qué utilizamos estrictamente tintas sin tolueno ni metales pesados ​​para todos nuestros productos de envasado de alimentos.', 'لا يتم إنشاء جميع الأحبار على قدم المساواة. اكتشف سبب استخدامنا الصارم للأحبار الخالية من التولوين والمعادن الثقيلة في جميع منتجات تغليف المواد الغذائية لدينا.', 'Not all inks are created equal. Discover why we strictly use toluene-free, heavy-metal-free inks for all our food packaging products.', 'No todas las tintas son iguales. Descubra por qué utilizamos estrictamente tintas sin tolueno ni metales pesados ​​para todos nuestros productos de envasado de alimentos.', 'لا يتم إنشاء جميع الأحبار على قدم المساواة. اكتشف سبب استخدامنا الصارم للأحبار الخالية من التولوين والمعادن الثقيلة في جميع منتجات تغليف المواد الغذائية لدينا.', '<p>Consumer safety is our top priority. We use only FDA and EU compliant inks that guarantee no chemical migration into the food. Our rigorous QC processes ensure that all printed materials are 100% safe and odor-free.</p>', '<p>La seguridad del consumidor es nuestra principal prioridad. Utilizamos únicamente tintas que cumplen con las normas de la FDA y la UE que garantizan que no haya migración química a los alimentos. Nuestros rigurosos procesos de control de calidad garantizan que todos los materiales impresos sean 100% seguros y libres de olores.</p>', '<p>سلامة المستهلك هي أولويتنا القصوى. نحن نستخدم فقط الأحبار المتوافقة مع إدارة الغذاء والدواء الأمريكية والاتحاد الأوروبي والتي تضمن عدم انتقال المواد الكيميائية إلى الطعام. تضمن عمليات مراقبة الجودة الصارمة لدينا أن جميع المواد المطبوعة آمنة وخالية من الروائح بنسبة 100%.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.08.10', '/images/factory/印刷车间/10001.png', '2026-04-29T13:50:47.739Z', '2026-05-04T12:08:51.862Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44phq000gtmnsttyuk09l', 'The Importance of Tear Notches', 'La importancia de las muescas de desgarro', 'أهمية الشقوق المسيل للدموع', 'importance-of-tear-notches', 'The Importance of Tear Notches', 'La importancia de las muescas de desgarro', 'أهمية الشقوق المسيل للدموع', 'A small detail that makes a huge difference. Tear notches greatly improve the consumer experience by allowing easy opening without scissors.', 'Un pequeño detalle que marca una gran diferencia. Las muescas para rasgar mejoran enormemente la experiencia del consumidor al permitir una fácil apertura sin tijeras.', 'تفصيلة صغيرة تصنع فرقاً كبيراً. تعمل الشقوق المسيلة للدموع على تحسين تجربة المستهلك بشكل كبير من خلال السماح بالفتح السهل بدون مقص.', 'A small detail that makes a huge difference. Tear notches greatly improve the consumer experience by allowing easy opening without scissors.', 'Un pequeño detalle que marca una gran diferencia. Las muescas para rasgar mejoran enormemente la experiencia del consumidor al permitir una fácil apertura sin tijeras.', 'تفصيلة صغيرة تصنع فرقاً كبيراً. تعمل الشقوق المسيلة للدموع على تحسين تجربة المستهلك بشكل كبير من خلال السماح بالفتح السهل بدون مقص.', '<p>We can add single or double tear notches to almost any pouch style. They are strategically placed above the zipper line, ensuring the consumer can easily access the product while retaining the resealable function.</p>', '<p>Podemos agregar muescas simples o dobles a casi cualquier estilo de bolsa. Están ubicados estratégicamente por encima de la línea de la cremallera, lo que garantiza que el consumidor pueda acceder fácilmente al producto manteniendo la función resellable.</p>', '<p>يمكننا إضافة شقوق مفردة أو مزدوجة إلى أي نمط من الحقائب تقريبًا. ويتم وضعها بشكل استراتيجي فوق خط السحاب، مما يضمن سهولة وصول المستهلك إلى المنتج مع الاحتفاظ بوظيفة إعادة الإغلاق.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.08.05', '/images/factory/印刷车间/10002.png', '2026-04-29T13:50:47.823Z', '2026-05-04T12:08:52.012Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pk1000htmnsuxxyhc2p', 'Packaging Solutions for Pet Food', 'Soluciones de envasado para alimentos para mascotas', 'حلول التعبئة والتغليف لأغذية الحيوانات الأليفة', 'packaging-solutions-for-pet-food', 'Packaging Solutions for Pet Food', 'Soluciones de envasado para alimentos para mascotas', 'حلول التعبئة والتغليف لأغذية الحيوانات الأليفة', 'Pet food requires heavy-duty packaging that can support large weights and block strong odors. Explore our specialized quad-seal and flat-bottom bags.', 'Los alimentos para mascotas requieren envases resistentes que puedan soportar grandes pesos y bloquear olores fuertes. Explore nuestras bolsas especializadas de fondo plano y con cierre cuádruple.', 'تتطلب أغذية الحيوانات الأليفة عبوات شديدة التحمل يمكنها تحمل الأوزان الكبيرة ومنع الروائح القوية. استكشف حقائبنا المخصصة ذات القاعدة الرباعية والمسطحة.', 'Pet food requires heavy-duty packaging that can support large weights and block strong odors. Explore our specialized quad-seal and flat-bottom bags.', 'Los alimentos para mascotas requieren envases resistentes que puedan soportar grandes pesos y bloquear olores fuertes. Explore nuestras bolsas especializadas de fondo plano y con cierre cuádruple.', 'تتطلب أغذية الحيوانات الأليفة عبوات شديدة التحمل يمكنها تحمل الأوزان الكبيرة ومنع الروائح القوية. استكشف حقائبنا المخصصة ذات القاعدة الرباعية والمسطحة.', '<p>Our pet food bags are engineered with high puncture resistance and strong side seals to prevent bursting. We also incorporate odor-barrier layers and heavy-duty slider zippers to keep kibble fresh and kitchens smelling clean.</p>', '<p>Nuestras bolsas de comida para mascotas están diseñadas con alta resistencia a perforaciones y fuertes sellos laterales para evitar explosiones. También incorporamos capas de barrera contra olores y cremalleras deslizantes resistentes para mantener las croquetas frescas y la cocina con un olor limpio.</p>', '<p>تم تصميم أكياس أغذية الحيوانات الأليفة لدينا بمقاومة عالية للثقب وأختام جانبية قوية لمنع الانفجار. نقوم أيضًا بدمج طبقات حاجزة للرائحة وسحابات منزلقة شديدة التحمل للحفاظ على الطعام طازجًا ورائحة المطابخ نظيفة.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.07.28', '/images/factory/印刷车间/10003.png', '2026-04-29T13:50:47.906Z', '2026-05-04T12:08:52.078Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pm4000itmnsto8dx04v', 'What are Shaped Pouches?', '¿Qué son las bolsas con forma?', 'ما هي الحقائب على شكل؟', 'what-are-shaped-pouches', 'What are Shaped Pouches?', '¿Qué son las bolsas con forma?', 'ما هي الحقائب على شكل؟', 'Break away from traditional squares and rectangles. Shaped pouches offer unique silhouettes that instantly grab attention on retail shelves.', 'Rompe con los cuadrados y rectángulos tradicionales. Las bolsas con formas ofrecen siluetas únicas que llaman instantáneamente la atención en los estantes de las tiendas minoristas.', 'ابتعد عن المربعات والمستطيلات التقليدية. توفر الأكياس ذات الأشكال صورًا ظلية فريدة تجذب الانتباه على الفور على أرفف البيع بالتجزئة.', 'Break away from traditional squares and rectangles. Shaped pouches offer unique silhouettes that instantly grab attention on retail shelves.', 'Rompe con los cuadrados y rectángulos tradicionales. Las bolsas con formas ofrecen siluetas únicas que llaman instantáneamente la atención en los estantes de las tiendas minoristas.', 'ابتعد عن المربعات والمستطيلات التقليدية. توفر الأكياس ذات الأشكال صورًا ظلية فريدة تجذب الانتباه على الفور على أرفف البيع بالتجزئة.', '<p>Using specialized die-cutting technology, we can manufacture pouches in almost any shape—from bottles and jars to fruits and brand mascots. Shaped pouches are highly popular in the cosmetics, children''s food, and beverage sectors.</p>', '<p>Utilizando tecnología de troquelado especializada, podemos fabricar bolsas en casi cualquier forma, desde botellas y frascos hasta frutas y mascotas de marcas. Las bolsas con forma son muy populares en los sectores de la cosmética, la alimentación infantil y las bebidas.</p>', '<p>باستخدام تقنية القطع بالقالب المتخصصة، يمكننا تصنيع الأكياس بأي شكل تقريبًا — بدءًا من الزجاجات والجرار وحتى الفواكه وتمائم العلامات التجارية. تحظى الأكياس ذات الأشكال بشعبية كبيرة في قطاعات مستحضرات التجميل وأغذية الأطفال والمشروبات.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.07.20', '/images/factory/印刷车间/10004.png', '2026-04-29T13:50:47.980Z', '2026-05-04T12:08:52.204Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44po7000jtmnsw8ciy1p2', 'HLT PACK''s Quality Control Process', 'Proceso de Control de Calidad de HLT PACK', 'عملية مراقبة الجودة في HLT PACK', 'hailitong-quality-control-process', 'HLT PACK''s Quality Control Process', 'Proceso de Control de Calidad de HLT PACK', 'عملية مراقبة الجودة في HLT PACK', 'Take a look inside our QA lab. From raw material inspection to final drop tests, we ensure every pouch meets the highest standards.', 'Eche un vistazo al interior de nuestro laboratorio de control de calidad. Desde la inspección de la materia prima hasta las pruebas finales de caída, nos aseguramos de que cada bolsa cumpla con los más altos estándares.', 'قم بإلقاء نظرة داخل مختبر ضمان الجودة لدينا. بدءًا من فحص المواد الخام وحتى اختبارات السقوط النهائية، نضمن أن كل كيس يلبي أعلى المعايير.', 'Take a look inside our QA lab. From raw material inspection to final drop tests, we ensure every pouch meets the highest standards.', 'Eche un vistazo al interior de nuestro laboratorio de control de calidad. Desde la inspección de la materia prima hasta las pruebas finales de caída, nos aseguramos de que cada bolsa cumpla con los más altos estándares.', 'قم بإلقاء نظرة داخل مختبر ضمان الجودة لدينا. بدءًا من فحص المواد الخام وحتى اختبارات السقوط النهائية، نضمن أن كل كيس يلبي أعلى المعايير.', '<p>Our comprehensive QC process includes tensile strength testing, heat seal integrity checks, barrier property analysis (OTR/WVTR), and simulated transport drop tests. We guarantee that your packaging will perform flawlessly on your filling line.</p>', '<p>Nuestro completo proceso de control de calidad incluye pruebas de resistencia a la tracción, comprobaciones de integridad del sellado térmico, análisis de propiedades de barrera (OTR/WVTR) y pruebas de caída simuladas durante el transporte. Garantizamos que su embalaje funcionará perfectamente en su línea de llenado.</p>', '<p>تتضمن عملية مراقبة الجودة الشاملة لدينا اختبار قوة الشد، وفحوصات سلامة الختم الحراري، وتحليل خصائص الحاجز (OTR/WVTR)، واختبارات محاكاة السقوط أثناء النقل. نحن نضمن أن التعبئة والتغليف الخاصة بك ستعمل بشكل لا تشوبه شائبة على خط التعبئة الخاص بك.</p>', 'FAQ', 'Preguntas frecuentes', 'التعليمات', '2024.07.15', '/images/factory/印刷车间/10005.png', '2026-04-29T13:50:48.056Z', '2026-05-04T12:08:52.314Z');

-- Insert or update banners
INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyv170000tmf8egiblxsa', 'Innovative Packaging', 'Embalaje innovador', 'التعبئة والتغليف المبتكرة', 'SMART DESIGN', 'DISEÑO INTELIGENTE', 'تصميم ذكي', 'Self-venting microwavable pouches combine convenience, reliable performance, and shelf-ready presentation.', 'Las bolsas para microondas con ventilación automática combinan comodidad, rendimiento confiable y presentación lista para usar en los estantes.', 'تجمع الأكياس القابلة للاستخدام في الميكروويف ذاتية التهوية بين الراحة والأداء الموثوق والعرض الجاهز للرف.', '/products/custom-food-bags/microwavable-retort-pouch/1.png', '/products/microwavable-retort-pouch', 1, 1, '2026-04-17T12:02:13.532Z', '2026-07-06T12:58:35.704Z');
INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyv3v0001tmf8or8i57zg', 'Circular Economy Solutions', 'Soluciones de economía circular', 'حلول الاقتصاد الدائري', 'RECYCLABLE BARRIER FILM', 'PELÍCULA BARRERA RECICLABLE', 'فيلم حاجز قابل لإعادة التدوير', 'Recyclable high-barrier ALOx-BOPP film supports circular packaging goals without compromising product protection.', 'La película reciclable ALOx-BOPP de alta barrera respalda los objetivos de embalaje circular sin comprometer la protección del producto.', 'يدعم فيلم ALOx-BOPP عالي الحاجز القابل لإعادة التدوير أهداف التغليف الدائري دون المساس بحماية المنتج.', '/products/recyclable-mono-materials/high-barrier-alox-bopp-film-recyclable-alox-bopp/1.png', '/products/high-barrier-alox-bopp-film-recyclable', 1, 2, '2026-04-17T12:02:13.628Z', '2026-07-06T12:58:35.704Z');
INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyv6a0002tmf8gg2q4xrd', 'Moisture Barrier Protection', 'Protección de barrera contra la humedad', 'حماية حاجز الرطوبة', 'HIGH-BARRIER SAFETY', 'SEGURIDAD DE ALTA BARRERA', 'أمان عالي الحواجز', 'High-barrier packaging protects sensitive products from moisture, oxygen, and environmental exposure.', 'Los envases de alta barrera protegen los productos sensibles de la humedad, el oxígeno y la exposición ambiental.', 'التغليف عالي الحاجز يحمي المنتجات الحساسة من الرطوبة والأكسجين والتعرض البيئي.', '/products/ziplock-bags/moisture-barrier-packaging-bag/1.png', '/products/moisture-barrier-packaging-bag', 1, 3, '2026-04-17T12:02:13.715Z', '2026-07-06T12:58:35.704Z');
INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyv9a0003tmf8tx59pa8a', 'Ready-to-eat Retort Pouches', 'Bolsas de retorta listas para comer', 'أكياس معوجة جاهزة للأكل', 'CONVENIENCE FIRST', 'LA CONVENIENCIA PRIMERO', 'الراحة أولاً', 'High-temperature resistant pouches designed for shelf-stable foods, ready meals, and demanding processing.', 'Bolsas resistentes a altas temperaturas diseñadas para alimentos no perecederos, comidas preparadas y procesamiento exigente.', 'أكياس مقاومة لدرجة الحرارة العالية مصممة للأطعمة القابلة للحفظ على الرف، والوجبات الجاهزة، والمعالجة الصعبة.', '/products/custom-food-bags/high-temperature-retort-pouch/1.png', '/products/high-temperature-retort-pouch', 1, 4, '2026-04-17T12:02:13.823Z', '2026-07-06T12:58:35.704Z');
INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyvcb0004tmf8m6z23890', 'Static-Safe Packaging', 'Embalaje antiestático', 'تغليف ثابت وآمن', 'ESD PROTECTION', 'PROTECCIÓN ESD', 'حماية البيئة والتنمية المستدامة', 'Multi-layer shielding bags protect sensitive electronics from static, moisture, and handling damage.', 'Las bolsas protectoras multicapa protegen los dispositivos electrónicos sensibles de la estática, la humedad y los daños por manipulación.', 'تعمل أكياس الحماية متعددة الطبقات على حماية الأجهزة الإلكترونية الحساسة من الكهرباء الساكنة والرطوبة والتعامل مع الأضرار.', '/products/ziplock-bags/anti-static-esd-shielding-bag/1.png', '/products/anti-static-esd-shielding-bag', 1, 5, '2026-04-17T12:02:13.931Z', '2026-07-06T12:58:35.704Z');

